"use strict";(globalThis.webpackChunkcybersec_kb=globalThis.webpackChunkcybersec_kb||[]).push([[77],{9933(e){e.exports=JSON.parse('{"tag":{"label":"attack","permalink":"/niebezpiecznik_szkolenie/pl/docs/tags/attack","allTagsPath":"/niebezpiecznik_szkolenie/pl/docs/tags","count":7,"items":[{"id":"theory/cryptographic-failures","title":"B\u0142\u0119dy kryptograficzne","description":"Cryptographic Failures (OWASP A02:2021) obejmuje s\u0142abe algorytmy, z\u0142\u0105 konfiguracj\u0119 TLS, niezabezpieczone przechowywanie hase\u0142 i wycieki sekret\xf3w w kodzie \u2014 wszystko to mo\u017ce prowadzi\u0107 do ujawnienia wra\u017cliwych danych.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/cryptographic-failures"},{"id":"theory/csrf","title":"CSRF \u2014 Cross-Site Request Forgery","description":"CSRF nak\u0142ania przegl\u0105dark\u0119 zalogowanego u\u017cytkownika do wys\u0142ania uwierzytelnionego \u017c\u0105dania do docelowej witryny bez jego wiedzy, poniewa\u017c przegl\u0105darki automatycznie do\u0142\u0105czaj\u0105 pliki cookie do pasuj\u0105cych \u017c\u0105da\u0144.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/csrf"},{"id":"theory/injection-xss","title":"Injection i XSS","description":"Ataki injection wstrzykuj\u0105 z\u0142o\u015bliwy kod do zaufanego kontekstu; XSS to wariant po stronie przegl\u0105darki, w kt\xf3rym skrypty kontrolowane przez atakuj\u0105cego wykonuj\u0105 si\u0119 w przegl\u0105darce ofiary.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/injection-xss"},{"id":"theory/iot-zero-day","title":"IoT, urz\u0105dzenia smart i zero-day","description":"Urz\u0105dzenia IoT rozszerzaj\u0105 powierzchni\u0119 ataku poprzez przestarza\u0142e oprogramowanie uk\u0142adowe i domy\u015blne dane uwierzytelniaj\u0105ce, co sprawia, \u017ce podatno\u015bci zero-day s\u0105 szczeg\xf3lnie niebezpieczne, poniewa\u017c te urz\u0105dzenia rzadko s\u0105 aktualizowane.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/iot-zero-day"},{"id":"theory/jwt","title":"JWT \u2014 JSON Web Token","description":"JWT to tr\xf3jcz\u0142onowy token zakodowany w base64, u\u017cywany do uwierzytelniania, jednak b\u0142\u0119dy konfiguracji \u2014 takie jak s\u0142abe sekrety lub atak alg:none \u2014 mog\u0105 pozwoli\u0107 atakuj\u0105cym na fa\u0142szowanie token\xf3w.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/jwt"},{"id":"theory/http-headers","title":"Nag\u0142\xf3wki HTTP i fa\u0142szowanie CF-Connecting-IP","description":"Je\u015bli serwer bezgranicznie ufa nag\u0142\xf3wkom IP, takim jak CF-Connecting-IP lub X-Forwarded-For, bez weryfikacji, \u017ce \u017c\u0105danie rzeczywi\u015bcie przysz\u0142o przez Cloudflare, atakuj\u0105cy mog\u0105 sfa\u0142szowa\u0107 dowolny adres IP.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/http-headers"},{"id":"theory/git-exposure","title":"Ujawnienie .git \u2014 wycieki kodu \u017ar\xf3d\u0142owego","description":"Ujawniony katalog .git/ na serwerze webowym pozwala atakuj\u0105cym zrekonstruowa\u0107 ca\u0142y kod \u017ar\xf3d\u0142owy aplikacji \u2014 \u0142\u0105cznie z sekretami i kluczami API z pe\u0142nej historii commit\xf3w.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/git-exposure"}],"unlisted":false}}')}}]);